    const h2 = line.match(/^## (.+)/);
    const h1 = line.match(/^# (.+)/);
    if (h1) { elements.push(<h1 key={key()} className="md-h1">{parseInline(h1[1])}</h1>); i++; continue; }
    if (h2) { elements.push(<h2 key={key()} className="md-h2">{parseInline(h2[1])}</h2>); i++; continue; }
